     1	import { useMemo, useState } from 'react';
     2	import { Link, useNavigate } from 'react-router-dom';
     3	import { useModelIndex, useModelStore, useModelDelete } from '@rhino-dev/rhino-react';
     4	import type { Project } from '../types';
     5	import { Icon } from '../components/Icons';
     6	import { useToast } from '../components/Toaster';
     7	import { fmtCurrency, fmtRelative } from '../lib/format';
     8	import { Loading, StatusPill } from './DashboardPage';
     9	
    10	const PER_PAGE = 10;
    11	type Sort = '-id' | 'title' | '-title' | 'status' | 'starts_at' | '-starts_at' | 'ends_at' | '-ends_at';
    12	
    13	export function ProjectsPage() {
    14	  const nav = useNavigate();
    15	  const toast = useToast();
    16	  const [search,  setSearch]  = useState('');
    17	  const [status,  setStatus]  = useState('');
    18	  const [sort,    setSort]    = useState<Sort>('title');
    19	  const [page,    setPage]    = useState(1);
    20	  const [showNew, setShowNew] = useState(false);
    21	
    22	  const filters = useMemo(() => {
    23	    const f: Record<string, string> = {};
    24	    if (status) f.status = status;
    25	    return f;
    26	  }, [status]);
    27	
    28	  const projects = useModelIndex<Project>('projects', {
    29	    filters,
    30	    search: search || undefined,
    31	    sort,
    32	    page,
    33	    perPage: PER_PAGE,
    34	  });
    35	
    36	  const store = useModelStore<Project>('projects');
    37	  const del   = useModelDelete<Project>('projects');
    38	
    39	  const list = projects.data?.data ?? [];
    40	  const pag  = projects.data?.pagination;
    41	
    42	  function onSortClick(field: Exclude<Sort, `-${string}`>) {
    43	    setSort(s => (s === field ? (`-${field}` as Sort) : field));
    44	  }
    45	
    46	  return (
    47	    <>
    48	      <div className="page-head">
    49	        <div>
    50	          <h1 className="page-title">Projects</h1>
    51	          <p className="page-sub">Multi-tenant scope: <span className="mono accent">/api/{`{org}`}/projects</span></p>
    52	        </div>
    53	        <button className="btn btn-primary" onClick={() => setShowNew(true)}><Icon.plus size={14} /> New project</button>
    54	      </div>
    55	
    56	      <div className="toolbar">
    57	        <input className="input input-search" style={{ flex: 1, maxWidth: 320 }} placeholder="Search title / description…" value={search} onChange={e => { setPage(1); setSearch(e.target.value); }} />
    58	        <select className="input select" value={status} onChange={e => { setPage(1); setStatus(e.target.value); }}>
    59	          <option value="">All statuses</option>
    60	          <option value="active">Active</option>
    61	          <option value="draft">Draft</option>
    62	          <option value="done">Done</option>
    63	          <option value="archived">Archived</option>
    64	        </select>
    65	        <span className="faint" style={{ marginLeft: 'auto', fontSize: 12 }}>
    66	          {projects.isFetching ? 'fetching…' : `${list.length} of ${pag?.total ?? list.length}`}
    67	        </span>
    68	      </div>
    69	
    70	      <div className="card" style={{ overflow: 'visible' }}>
    71	        {projects.isLoading ? <Loading /> : list.length === 0 ? (
    72	          <div className="empty"><h3>No projects match</h3><p>Try a different filter, or create one.</p></div>
    73	        ) : (
    74	          <table className="table">
    75	            <thead>
    76	              <tr>
    77	                <Th label="Title"   field="title"      sort={sort} onClick={onSortClick} />
    78	                <Th label="Status"  field="status"     sort={sort} onClick={onSortClick} />
    79	                <Th label="Budget"  field={null} />
    80	                <Th label="Starts"  field="starts_at"  sort={sort} onClick={onSortClick} />
    81	                <Th label="Ends"    field="ends_at"    sort={sort} onClick={onSortClick} />
    82	                <Th label="Updated" field={null} />
    83	                <th style={{ width: 60 }}></th>
    84	              </tr>
    85	            </thead>
    86	            <tbody>
    87	              {list.map(p => (
    88	                <tr key={p.id} onClick={() => nav(`/projects/${p.id}`)}>
    89	                  <td>
    90	                    <Link to={`/projects/${p.id}`} onClick={e => e.stopPropagation()} style={{ fontWeight: 600 }}>{p.title}</Link>
    91	                    <div className="faint" style={{ fontSize: 11, marginTop: 2 }}>{p.description?.slice(0, 90)}</div>
    92	                  </td>
    93	                  <td><StatusPill value={p.status} /></td>
    94	                  <td>{p.budget != null ? fmtCurrency(p.budget) : <span className="rbac-hidden">hidden</span>}</td>
    95	                  <td className="faint">{p.starts_at?.slice(0, 10) ?? '—'}</td>
    96	                  <td className="faint">{p.ends_at?.slice(0, 10) ?? '—'}</td>
    97	                  <td className="faint">{fmtRelative(p.updated_at)}</td>
    98	                  <td>
    99	                    <button
   100	                      className="btn btn-ghost btn-icon"
   101	                      title="Soft delete (move to trash)"
   102	                      onClick={async e => {
   103	                        e.stopPropagation();
   104	                        if (!confirm(`Delete project "${p.title}"?`)) return;
   105	                        try {
   106	                          await del.mutateAsync(p.id);
   107	                          toast(`Deleted "${p.title}"`, 'ok');
   108	                        } catch (err) {
   109	                          toast(`Delete failed: ${(err as Error).message}`, 'error');
   110	                        }
   111	                      }}
   112	                    >
   113	                      <Icon.trash size={14} />
   114	                    </button>
   115	                  </td>
   116	                </tr>
   117	              ))}
   118	            </tbody>
   119	          </table>
   120	        )}
   121	
   122	        {pag && pag.lastPage > 1 && (
   123	          <div className="pager">
   124	            <div className="pager-info">Page {pag.currentPage} of {pag.lastPage} · {pag.total} total</div>
   125	            <div className="pager-ctrls">
   126	              <button className="btn btn-sm" disabled={page <= 1} onClick={() => setPage(p => p - 1)}><Icon.arrowL size={12} /></button>
   127	              <button className="btn btn-sm" disabled={page >= pag.lastPage} onClick={() => setPage(p => p + 1)}><Icon.arrowR size={12} /></button>
   128	            </div>
   129	          </div>
   130	        )}
   131	      </div>
   132	
   133	      {showNew && (
   134	        <NewProjectModal
   135	          onClose={() => setShowNew(false)}
   136	          onCreate={async data => {
   137	            try {
   138	              const created = await store.mutateAsync(data);
   139	              toast(`Created "${created.title}"`, 'ok');
   140	              setShowNew(false);
   141	            } catch (err) {
   142	              toast(`Create failed: ${(err as Error).message}`, 'error');
   143	            }
   144	          }}
   145	          busy={store.isPending}
   146	        />
   147	      )}
   148	    </>
   149	  );
   150	}
   151	
   152	function Th(props: { label: string; field: string | null; sort?: string; onClick?: (f: any) => void }) {
   153	  const { label, field, sort, onClick } = props;
   154	  if (!field || !onClick) return <th>{label}</th>;
   155	  const active = sort === field || sort === `-${field}`;
   156	  return (
   157	    <th className={active ? 'sorted' : ''} onClick={() => onClick(field)}>
   158	      {label}
   159	      <span className="sort-arrow">{active ? (sort === field ? '↑' : '↓') : '↕'}</span>
   160	    </th>
   161	  );
   162	}
   163	
   164	function NewProjectModal({ onClose, onCreate, busy }: { onClose: () => void; onCreate: (data: Partial<Project>) => Promise<void>; busy: boolean }) {
   165	  const [title, setTitle]   = useState('');
   166	  const [status, setStatus] = useState<Project['status']>('draft');
   167	  const [desc, setDesc]     = useState('');
   168	  return (
   169	    <div className="modal-backdrop" onClick={onClose}>
   170	      <div className="modal" onClick={e => e.stopPropagation()}>
   171	        <div className="modal-head">
   172	          <div className="modal-title">New project</div>
   173	          <button className="btn btn-ghost btn-icon" onClick={onClose}><Icon.close /></button>
   174	        </div>
   175	        <div className="modal-body">
   176	          <form className="form" onSubmit={e => { e.preventDefault(); onCreate({ title, status, description: desc }); }}>
   177	            <div className="field">
   178	              <label>Title</label>
   179	              <input className="input" value={title} onChange={e => setTitle(e.target.value)} required autoFocus />
   180	            </div>
   181	            <div className="field">
   182	              <label>Status</label>
   183	              <select className="input select" value={status} onChange={e => setStatus(e.target.value)}>
   184	                <option value="draft">Draft</option>
   185	                <option value="active">Active</option>
   186	                <option value="done">Done</option>
   187	                <option value="archived">Archived</option>
   188	              </select>
   189	            </div>
   190	            <div className="field">
   191	              <label>Description</label>
   192	              <textarea className="input" rows={3} value={desc} onChange={e => setDesc(e.target.value)} />
   193	            </div>
   194	            <div className="modal-foot" style={{ padding: 0, border: 0 }}>
   195	              <button type="button" className="btn btn-ghost" onClick={onClose}>Cancel</button>
   196	              <button type="submit" className="btn btn-primary" disabled={busy}>{busy ? <span className="spinner" /> : <Icon.check size={14} />} Create</button>
   197	            </div>
   198	          </form>
   199	        </div>
   200	      </div>
   201	    </div>
   202	  );
   203	}
